import { NativeModules, Platform } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const SENSITIVE_KEYS = ['token', 'password', 'auth', 'secret', 'key', 'credential', 'ssn', 'credit'];
const MAX_LOG_SIZE = 1000;
const LOG_RETENTION_DAYS = 7;

class SecureDebugLogger {
  constructor() {
    this.logs = [];
    this.isProduction = !__DEV__;
    this.sessionId = this.generateSessionId();
    this.userId = null;
  }

  generateSessionId() {
    return `session_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  }

  sanitizeData(data) {
    if (!data) return data;
    
    const sanitize = (obj) => {
      if (typeof obj !== 'object' || obj === null) return obj;
      
      const sanitized = Array.isArray(obj) ? [] : {};
      
      for (const key in obj) {
        const lowerKey = key.toLowerCase();
        const isSensitive = SENSITIVE_KEYS.some(sensitive => lowerKey.includes(sensitive));
        
        if (isSensitive) {
          sanitized[key] = '[REDACTED]';
        } else if (typeof obj[key] === 'object' && obj[key] !== null) {
          sanitized[key] = sanitize(obj[key]);
        } else {
          sanitized[key] = obj[key];
        }
      }
      
      return sanitized;
    };
    
    return sanitize(data);
  }

  sanitizeUrl(url) {
    try {
      const urlObj = new URL(url);
      const sensitiveParams = ['token', 'key', 'secret', 'password'];
      
      sensitiveParams.forEach(param => {
        if (urlObj.searchParams.has(param)) {
          urlObj.searchParams.set(param, '[REDACTED]');
        }
      });
      
      return urlObj.toString();
    } catch {
      return url;
    }
  }

  addLog(level, category, message, metadata = {}) {
    const logEntry = {
      timestamp: new Date().toISOString(),
      level,
      category,
      message,
      metadata: this.sanitizeData(metadata),
      sessionId: this.sessionId,
      userId: this.userId ? `user_${this.userId.substr(0, 8)}` : 'anonymous',
      platform: Platform.OS,
      version: Platform.Version
    };

    this.logs.push(logEntry);

    if (this.logs.length > MAX_LOG_SIZE) {
      this.logs.shift();
    }

    if (!this.isProduction) {
      console.log(`[${level}] ${category}:`, message, metadata);
    }

    this.persistLogs();
  }

  async persistLogs() {
    try {
      const logsToStore = this.logs.slice(-100);
      await AsyncStorage.setItem('debug_logs', JSON.stringify(logsToStore));
    } catch (error) {
      // Silent fail
    }
  }

  async loadLogs() {
    try {
      const stored = await AsyncStorage.getItem('debug_logs');
      if (stored) {
        this.logs = JSON.parse(stored);
      }
    } catch (error) {
      // Silent fail
    }
  }

  logNetworkRequest(config) {
    const sanitizedConfig = {
      method: config.method,
      url: this.sanitizeUrl(config.url),
      headers: this.sanitizeData(config.headers),
      timestamp: Date.now()
    };

    this.addLog('INFO', 'NETWORK_REQUEST', 'API Request', sanitizedConfig);
    return sanitizedConfig.timestamp;
  }

  logNetworkResponse(requestTimestamp, response, error = null) {
    const duration = Date.now() - requestTimestamp;
    
    if (error) {
      this.addLog('ERROR', 'NETWORK_RESPONSE', 'API Request Failed', {
        duration,
        status: error.response?.status,
        message: error.message,
        code: error.code
      });
    } else {
      this.addLog('INFO', 'NETWORK_RESPONSE', 'API Request Success', {
        duration,
        status: response.status,
        dataSize: JSON.stringify(response.data || {}).length
      });
    }
  }

  logAsyncStorageOperation(operation, key, success, error = null) {
    const sanitizedKey = SENSITIVE_KEYS.some(s => key.toLowerCase().includes(s)) 
      ? '[REDACTED_KEY]' 
      : key;

    this.addLog(
      success ? 'INFO' : 'ERROR',
      'ASYNC_STORAGE',
      `${operation} operation`,
      {
        key: sanitizedKey,
        success,
        error: error?.message
      }
    );
  }

  logUserAction(action, screen, metadata = {}) {
    this.addLog('INFO', 'USER_ACTION', action, {
      screen,
      ...this.sanitizeData(metadata)
    });
  }

  logStateChange(component, previousState, newState) {
    this.addLog('DEBUG', 'STATE_CHANGE', `${component} state updated`, {
      hasChanges: true,
      stateKeys: Object.keys(newState || {})
    });
  }

  logError(error, context = {}) {
    this.addLog('ERROR', 'APPLICATION_ERROR', error.message, {
      stack: error.stack?.split('\n').slice(0, 5).join('\n'),
      context: this.sanitizeData(context)
    });
  }

  setUserId(userId) {
    this.userId = userId;
  }

  async exportLogsForSupport() {
    const exportData = {
      sessionId: this.sessionId,
      exportedAt: new Date().toISOString(),
      platform: Platform.OS,
      version: Platform.Version,
      logs: this.logs.slice(-200)
    };

    return JSON.stringify(exportData, null, 2);
  }

  async clearLogs() {
    this.logs = [];
    await AsyncStorage.removeItem('debug_logs');
  }

  getRecentLogs(count = 50) {
    return this.logs.slice(-count);
  }
}

const logger = new SecureDebugLogger();

export const initializeLogger = async () => {
  await logger.loadLogs();
};

export const logNetworkRequest = (config) => logger.logNetworkRequest(config);
export const logNetworkResponse = (timestamp, response, error) => 
  logger.logNetworkResponse(timestamp, response, error);
export const logAsyncStorage = (operation, key, success, error) => 
  logger.logAsyncStorageOperation(operation, key, success, error);
export const logUserAction = (action, screen, metadata) => 
  logger.logUserAction(action, screen, metadata);
export const logStateChange = (component, prevState, newState) => 
  logger.logStateChange(component, prevState, newState);
export const logError = (error, context) => logger.logError(error, context);
export const setUserId = (userId) => logger.setUserId(userId);
export const exportLogs = () => logger.exportLogsForSupport();
export const clearLogs = () => logger.clearLogs();
export const getRecentLogs = (count) => logger.getRecentLogs(count);

export default logger;